const config = {
  supplier_name: 'HLC.ME',
  supplier_id: '29955',
  lookback_weeks: 52,
  top_states: 10,
  top_skus_per_state: 5,
  state_field_override: '',
  sku_field_override: '',
  sku_name_field_override: '',
  quantity_field_override: ''
};

return [{ json: config }];

const discovery = $input.first().json;
const config = $('Report Config').first().json;

function splitCandidates(value) {
  return String(value || '')
    .split('\n')
    .map((entry) => entry.trim())
    .filter(Boolean);
}

function normalisePath(value) {
  return String(value || '').trim().replace(/^retail_sku_store_date\./, '');
}

function dedupe(values) {
  return [...new Set(values.map(normalisePath).filter(Boolean))];
}

function pickCandidate(candidates, preferredSuffixes, blockedFragments) {
  const blocked = blockedFragments || [];
  const scored = dedupe(candidates).map((candidate) => {
    const lower = candidate.toLowerCase();
    let score = 0;

    preferredSuffixes.forEach((suffix, index) => {
      if (lower === suffix || lower.endsWith(`.${suffix}`)) {
        score += 200 - index;
      } else if (lower.includes(suffix)) {
        score += 40 - index;
      }
    });

    if (lower.startsWith('supplier_struct.supplier_part_struct.orders.')) score += 40;
    if (lower.startsWith('supplier_struct.supplier_part_struct.')) score += 30;
    if (lower.startsWith('supplier_struct.')) score += 20;
    if (!candidate.includes('.')) score += 10;

    blocked.forEach((fragment) => {
      if (lower.includes(fragment)) score -= 500;
    });

    return { candidate, score };
  });

  scored.sort((left, right) => right.score - left.score || left.candidate.localeCompare(right.candidate));
  return scored[0] ? scored[0].candidate : '';
}

const candidates = {
  state: splitCandidates(discovery.state_candidates),
  sku: splitCandidates(discovery.sku_candidates),
  skuName: splitCandidates(discovery.sku_name_candidates),
  quantity: splitCandidates(discovery.quantity_candidates),
};

const warnings = [];
const joins = new Map();

function resolveExpression(fieldPath) {
  const normalised = normalisePath(fieldPath);
  if (!normalised) {
    return '';
  }

  const directMappings = [
    ['supplier_struct.supplier_part_struct.orders.', 'orders.'],
    ['orders.', 'orders.'],
    ['supplier_struct.supplier_part_struct.', 'supplier_part_struct.'],
    ['supplier_part_struct.', 'supplier_part_struct.'],
    ['supplier_struct.', 'supplier_struct.'],
    ['traffic_source.', 'traffic_source.'],
  ];

  for (const [prefix, replacement] of directMappings) {
    if (normalised.startsWith(prefix)) {
      if (prefix === 'traffic_source.') {
        joins.set('traffic_source', 'LEFT JOIN UNNEST(retail_sku_store_date.traffic_source) AS traffic_source');
      }
      return replacement + normalised.slice(prefix.length);
    }
  }

  if (normalised.startsWith('store_struct.')) {
    joins.set('store_struct', 'LEFT JOIN UNNEST(retail_sku_store_date.store_struct) AS store_struct');
    return 'store_struct.' + normalised.slice('store_struct.'.length);
  }

  if (normalised.startsWith('stores.')) {
    joins.set('stores', 'LEFT JOIN UNNEST(retail_sku_store_date.stores) AS stores');
    return 'stores.' + normalised.slice('stores.'.length);
  }

  return `retail_sku_store_date.${normalised}`;
}

const stateField = normalisePath(config.state_field_override) || pickCandidate(
  candidates.state,
  ['state_name', 'ship_to_state', 'destination_state', 'customer_state', 'order_state', 'bill_to_state', 'store_state_name', 'state', 'state_code', 'statecode'],
  ['styname', 'statement', 'country']
);

const skuField = normalisePath(config.sku_field_override) || pickCandidate(
  candidates.sku,
  ['sku_id', 'skuid', 'sku', 'part_number', 'partnumber', 'supplier_part_id', 'supplierpartid', 'product_id', 'item_id', 'id'],
  []
);

const skuNameField = normalisePath(config.sku_name_field_override) || pickCandidate(
  candidates.skuName,
  ['sku_name', 'skuname', 'product_name', 'productname', 'part_name', 'partname', 'item_name', 'itemname', 'product_title'],
  []
);

const quantityField = normalisePath(config.quantity_field_override) || pickCandidate(
  candidates.quantity,
  ['quantity', 'qty', 'units', 'unit_count'],
  []
);

if (!stateField) {
  throw new Error(`Unable to auto-detect a state field. Populate state_field_override in the Report Config node. Discovery result: ${JSON.stringify(candidates.state)}`);
}

if (!skuField) {
  throw new Error(`Unable to auto-detect a SKU key field. Populate sku_field_override in the Report Config node. Discovery result: ${JSON.stringify(candidates.sku)}`);
}

const stateExpression = resolveExpression(stateField);
const skuExpression = resolveExpression(skuField);
const skuNameExpression = skuNameField ? resolveExpression(skuNameField) : skuExpression;
let quantityExpression = '0';

if (quantityField) {
  quantityExpression = `COALESCE(CAST(${resolveExpression(quantityField)} AS NUMERIC), 0)`;
} else {
  warnings.push('No quantity field was detected automatically, so units_sold will be 0 unless quantity_field_override is set.');
}

if (!skuNameField) {
  warnings.push('No SKU name field was detected automatically, so SKU labels will mirror the SKU key field.');
}

const supplierName = String(config.supplier_name || '').trim();
const supplierId = String(config.supplier_id || '').trim();
const lookbackWeeks = Number(config.lookback_weeks || 52);
const topStates = Number(config.top_states || 10);
const topSkusPerState = Number(config.top_skus_per_state || 5);

if (!supplierName && !supplierId) {
  throw new Error('Set supplier_name, supplier_id, or both in the Report Config node.');
}

const sqlQuery = `DECLARE supplier_name_input STRING DEFAULT ${JSON.stringify(supplierName)};
DECLARE supplier_id_input STRING DEFAULT ${JSON.stringify(supplierId)};
DECLARE lookback_weeks_input INT64 DEFAULT ${Number.isFinite(lookbackWeeks) ? lookbackWeeks : 52};

WITH params AS (
  SELECT
    supplier_name_input AS supplier_name,
    supplier_id_input AS supplier_id,
    DATE_SUB(CURRENT_DATE(), INTERVAL lookback_weeks_input WEEK) AS start_date,
    CURRENT_DATE() AS end_date
),
currency AS (
  SELECT
    ANY_VALUE(ExchangeRate) AS exchange_rate,
    ANY_VALUE(currency_symbol) AS currency_symbol
  FROM \`wf-gcp-us-ae-retail-prod.cm_reporting.vw_local_currency_conversion\`
  WHERE CuyShortName = 'USD'
),
base_rows AS (
  SELECT
    retail_dim_supplier.origsuname AS supplier_name,
    CAST(retail_dim_supplier.origsuid AS STRING) AS supplier_id,
    COALESCE(NULLIF(TRIM(CAST(${stateExpression} AS STRING)), ''), 'Unknown') AS state_name,
    COALESCE(NULLIF(TRIM(CAST(${skuExpression} AS STRING)), ''), 'Unknown SKU') AS sku_key,
    COALESCE(NULLIF(TRIM(CAST(${skuNameExpression} AS STRING)), ''), COALESCE(NULLIF(TRIM(CAST(${skuExpression} AS STRING)), ''), 'Unknown SKU')) AS sku_name,
    orders.id AS order_id,
    ${quantityExpression} AS units_sold,
    COALESCE(orders.grossrevenuestable, 0) * COALESCE(currency.exchange_rate, 1) AS gross_revenue,
    currency.currency_symbol AS currency_symbol,
    DATE(retail_sku_store_date.date) AS order_date
  FROM \`wf-gcp-us-ae-retail-prod.cm_reporting.retail_sku_store_date_agg\` AS retail_sku_store_date
  LEFT JOIN UNNEST(retail_sku_store_date.supplier_struct) AS supplier_struct
  LEFT JOIN UNNEST(supplier_struct.supplier_part_struct) AS supplier_part_struct
  LEFT JOIN UNNEST(supplier_part_struct.orders) AS orders
  ${Array.from(joins.values()).join('\n  ')}
  LEFT JOIN \`wf-gcp-us-ae-retail-prod.cm_reporting.retail_dim_supplier\` AS retail_dim_supplier
    ON retail_dim_supplier.supplierkey = supplier_struct.supplierkey
  CROSS JOIN currency
  CROSS JOIN params
  WHERE retail_sku_store_date.brandname = 'Wayfair'
    AND retail_sku_store_date.agg_level = 'DAILY'
    AND DATE(retail_sku_store_date.date) BETWEEN params.start_date AND params.end_date
    AND (
      (params.supplier_id <> '' AND CAST(retail_dim_supplier.origsuid AS STRING) = params.supplier_id)
      OR (params.supplier_name <> '' AND LOWER(retail_dim_supplier.origsuname) = LOWER(params.supplier_name))
    )
),
deduped_sales AS (
  SELECT
    supplier_name,
    supplier_id,
    state_name,
    sku_key,
    sku_name,
    currency_symbol,
    order_id,
    ANY_VALUE(units_sold) AS units_sold,
    ANY_VALUE(gross_revenue) AS gross_revenue,
    MIN(order_date) AS first_order_date,
    MAX(order_date) AS last_order_date
  FROM base_rows
  WHERE order_id IS NOT NULL
  GROUP BY
    supplier_name,
    supplier_id,
    state_name,
    sku_key,
    sku_name,
    currency_symbol,
    order_id
),
sku_state_sales AS (
  SELECT
    supplier_name,
    supplier_id,
    state_name,
    sku_key,
    sku_name,
    currency_symbol,
    COUNT(DISTINCT order_id) AS order_count,
    SUM(units_sold) AS units_sold,
    SUM(gross_revenue) AS gross_revenue,
    MIN(first_order_date) AS first_order_date,
    MAX(last_order_date) AS last_order_date
  FROM deduped_sales
  GROUP BY
    supplier_name,
    supplier_id,
    state_name,
    sku_key,
    sku_name,
    currency_symbol
)
SELECT
  supplier_name,
  supplier_id,
  state_name,
  sku_key,
  sku_name,
  currency_symbol,
  order_count,
  units_sold,
  gross_revenue,
  first_order_date,
  last_order_date
FROM sku_state_sales
ORDER BY gross_revenue DESC, units_sold DESC, state_name, sku_name;`;

return [{
  json: {
    sqlQuery,
    metadata: {
      supplier_name: supplierName,
      supplier_id: supplierId,
      lookback_weeks: Number.isFinite(lookbackWeeks) ? lookbackWeeks : 52,
      top_states: Number.isFinite(topStates) ? topStates : 10,
      top_skus_per_state: Number.isFinite(topSkusPerState) ? topSkusPerState : 5,
      warnings,
      resolved_fields: {
        state_field: stateField,
        sku_field: skuField,
        sku_name_field: skuNameField || '',
        quantity_field: quantityField || ''
      },
      discovery_candidates: candidates
    }
  }
}];

const rows = $input.all().map((item) => item.json);
const queryConfig = $('Build Sales Query').first().json;
const metadata = queryConfig.metadata || {};

function toNumber(value) {
  const number = Number(value || 0);
  return Number.isFinite(number) ? number : 0;
}

function money(value, symbol) {
  return `${symbol}${toNumber(value).toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 })}`;
}

function number(value) {
  return toNumber(value).toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 });
}

function percent(value) {
  return `${(toNumber(value) * 100).toFixed(1)}%`;
}

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function makeMarkdownTable(headers, tableRows) {
  const headerLine = `| ${headers.join(' | ')} |`;
  const divider = `| ${headers.map(() => '---').join(' | ')} |`;
  const body = tableRows.map((row) => `| ${row.join(' | ')} |`).join('\n');
  return [headerLine, divider, body].filter(Boolean).join('\n');
}

function makeHtmlTable(headers, tableRows) {
  const headerHtml = headers.map((header) => `<th>${escapeHtml(header)}</th>`).join('');
  const bodyHtml = tableRows
    .map((row) => `<tr>${row.map((cell) => `<td>${escapeHtml(cell)}</td>`).join('')}</tr>`)
    .join('');
  return `<table><thead><tr>${headerHtml}</tr></thead><tbody>${bodyHtml}</tbody></table>`;
}

const normalisedRows = rows.map((row) => ({
  supplier_name: row.supplier_name || metadata.supplier_name || '',
  supplier_id: String(row.supplier_id || metadata.supplier_id || ''),
  state_name: row.state_name || 'Unknown',
  sku_key: row.sku_key || 'Unknown SKU',
  sku_name: row.sku_name || row.sku_key || 'Unknown SKU',
  currency_symbol: row.currency_symbol || '$',
  order_count: toNumber(row.order_count),
  units_sold: toNumber(row.units_sold),
  gross_revenue: toNumber(row.gross_revenue),
  first_order_date: row.first_order_date || '',
  last_order_date: row.last_order_date || ''
}));

if (normalisedRows.length === 0) {
  const noResultsMessage = `# Supplier SKU State Sales Report\n\nNo rows were returned for ${metadata.supplier_name || 'the requested supplier'} (${metadata.supplier_id || 'no supplier ID supplied'}) across the last ${metadata.lookback_weeks || 52} weeks.`;
  const warningLines = (metadata.warnings || []).map((warning) => `- ${warning}`).join('\n');
  return [{
    json: {
      metadata,
      warnings: metadata.warnings || [],
      markdownReport: [noResultsMessage, warningLines && `\n## Warnings\n${warningLines}`].filter(Boolean).join('\n'),
      htmlReport: `<h1>Supplier SKU State Sales Report</h1><p>No rows were returned for ${escapeHtml(metadata.supplier_name || 'the requested supplier')} (${escapeHtml(metadata.supplier_id || 'no supplier ID supplied')}) across the last ${escapeHtml(String(metadata.lookback_weeks || 52))} weeks.</p>`,
      overallTotals: { gross_revenue: 0, units_sold: 0, order_count: 0, state_count: 0, sku_count: 0 },
      stateTotals: [],
      skuSummary: [],
      topSkusByState: [],
      skuStateDetail: []
    }
  }];
}

normalisedRows.sort((left, right) => right.gross_revenue - left.gross_revenue || right.units_sold - left.units_sold || left.state_name.localeCompare(right.state_name));
const currencySymbol = normalisedRows[0].currency_symbol || '$';
const overall = { gross_revenue: 0, units_sold: 0, order_count: 0, state_count: 0, sku_count: 0 };
const stateMap = new Map();
const skuMap = new Map();

for (const row of normalisedRows) {
  overall.gross_revenue += row.gross_revenue;
  overall.units_sold += row.units_sold;
  overall.order_count += row.order_count;

  if (!stateMap.has(row.state_name)) {
    stateMap.set(row.state_name, {
      state_name: row.state_name,
      gross_revenue: 0,
      units_sold: 0,
      order_count: 0,
      sku_map: new Map()
    });
  }

  if (!skuMap.has(row.sku_key)) {
    skuMap.set(row.sku_key, {
      sku_key: row.sku_key,
      sku_name: row.sku_name,
      gross_revenue: 0,
      units_sold: 0,
      order_count: 0,
      state_map: new Map()
    });
  }

  const stateEntry = stateMap.get(row.state_name);
  stateEntry.gross_revenue += row.gross_revenue;
  stateEntry.units_sold += row.units_sold;
  stateEntry.order_count += row.order_count;

  const stateSkuKey = `${row.sku_key}::${row.sku_name}`;
  if (!stateEntry.sku_map.has(stateSkuKey)) {
    stateEntry.sku_map.set(stateSkuKey, {
      sku_key: row.sku_key,
      sku_name: row.sku_name,
      gross_revenue: 0,
      units_sold: 0,
      order_count: 0
    });
  }
  const stateSkuEntry = stateEntry.sku_map.get(stateSkuKey);
  stateSkuEntry.gross_revenue += row.gross_revenue;
  stateSkuEntry.units_sold += row.units_sold;
  stateSkuEntry.order_count += row.order_count;

  const skuEntry = skuMap.get(row.sku_key);
  skuEntry.gross_revenue += row.gross_revenue;
  skuEntry.units_sold += row.units_sold;
  skuEntry.order_count += row.order_count;

  if (!skuEntry.state_map.has(row.state_name)) {
    skuEntry.state_map.set(row.state_name, {
      state_name: row.state_name,
      gross_revenue: 0,
      units_sold: 0,
      order_count: 0
    });
  }
  const skuStateEntry = skuEntry.state_map.get(row.state_name);
  skuStateEntry.gross_revenue += row.gross_revenue;
  skuStateEntry.units_sold += row.units_sold;
  skuStateEntry.order_count += row.order_count;
}

const stateTotals = Array.from(stateMap.values()).map((entry) => {
  const topSkus = Array.from(entry.sku_map.values())
    .sort((left, right) => right.gross_revenue - left.gross_revenue || right.units_sold - left.units_sold)
    .map((sku, index) => ({
      rank: index + 1,
      sku_key: sku.sku_key,
      sku_name: sku.sku_name,
      gross_revenue: sku.gross_revenue,
      units_sold: sku.units_sold,
      order_count: sku.order_count,
      revenue_share_of_state: entry.gross_revenue ? sku.gross_revenue / entry.gross_revenue : 0
    }));

  return {
    state_name: entry.state_name,
    gross_revenue: entry.gross_revenue,
    units_sold: entry.units_sold,
    order_count: entry.order_count,
    sku_count: topSkus.length,
    revenue_share_of_supplier: overall.gross_revenue ? entry.gross_revenue / overall.gross_revenue : 0,
    top_sku: topSkus[0] || null,
    top_skus: topSkus.slice(0, metadata.top_skus_per_state || 5)
  };
}).sort((left, right) => right.gross_revenue - left.gross_revenue || right.units_sold - left.units_sold || left.state_name.localeCompare(right.state_name));

const skuSummary = Array.from(skuMap.values()).map((entry) => {
  const rankedStates = Array.from(entry.state_map.values())
    .sort((left, right) => right.gross_revenue - left.gross_revenue || right.units_sold - left.units_sold || left.state_name.localeCompare(right.state_name))
    .map((state, index) => ({
      rank: index + 1,
      state_name: state.state_name,
      gross_revenue: state.gross_revenue,
      units_sold: state.units_sold,
      order_count: state.order_count,
      revenue_share_of_sku: entry.gross_revenue ? state.gross_revenue / entry.gross_revenue : 0
    }));

  return {
    sku_key: entry.sku_key,
    sku_name: entry.sku_name,
    gross_revenue: entry.gross_revenue,
    units_sold: entry.units_sold,
    order_count: entry.order_count,
    state_count: rankedStates.length,
    revenue_share_of_supplier: overall.gross_revenue ? entry.gross_revenue / overall.gross_revenue : 0,
    top_state: rankedStates[0] || null,
    ranked_states: rankedStates
  };
}).sort((left, right) => right.gross_revenue - left.gross_revenue || right.units_sold - left.units_sold || left.sku_name.localeCompare(right.sku_name));

overall.state_count = stateTotals.length;
overall.sku_count = skuSummary.length;

const stateHighlights = stateTotals.slice(0, metadata.top_states || 10).map((entry, index) => {
  const leadSku = entry.top_sku ? `${entry.top_sku.sku_name} (${money(entry.top_sku.gross_revenue, currencySymbol)})` : 'No lead SKU';
  return `${index + 1}. ${entry.state_name}: ${money(entry.gross_revenue, currencySymbol)} from ${number(entry.units_sold)} units across ${number(entry.order_count)} orders. Lead SKU: ${leadSku}.`;
});

const stateTableRows = stateTotals.slice(0, metadata.top_states || 10).map((entry, index) => [
  String(index + 1),
  entry.state_name,
  money(entry.gross_revenue, currencySymbol),
  number(entry.units_sold),
  number(entry.order_count),
  String(entry.sku_count),
  entry.top_sku ? `${entry.top_sku.sku_name} (${percent(entry.top_sku.revenue_share_of_state)})` : 'N/A'
]);

const skuTableRows = skuSummary.slice(0, 25).map((entry) => [
  entry.sku_key,
  entry.sku_name,
  money(entry.gross_revenue, currencySymbol),
  number(entry.units_sold),
  number(entry.order_count),
  entry.top_state ? entry.top_state.state_name : 'N/A',
  entry.top_state ? money(entry.top_state.gross_revenue, currencySymbol) : 'N/A',
  entry.top_state ? percent(entry.top_state.revenue_share_of_sku) : 'N/A'
]);

const resolvedFieldLines = Object.entries(metadata.resolved_fields || {}).map(([key, value]) => `- ${key}: ${value || 'not set'}`);
const warningLines = (metadata.warnings || []).map((warning) => `- ${warning}`);

const markdownSections = [
  '# Supplier SKU State Sales Report',
  `Supplier: ${metadata.supplier_name || normalisedRows[0].supplier_name} (${metadata.supplier_id || normalisedRows[0].supplier_id})`,
  `Window: last ${metadata.lookback_weeks || 52} weeks`,
  '',
  '## Overall totals',
  `- Gross revenue: ${money(overall.gross_revenue, currencySymbol)}`,
  `- Units sold: ${number(overall.units_sold)}`,
  `- Orders: ${number(overall.order_count)}`,
  `- States with sales: ${number(overall.state_count)}`,
  `- SKUs with sales: ${number(overall.sku_count)}`,
  '',
  '## States ranked by revenue',
  makeMarkdownTable(['Rank', 'State', 'Revenue', 'Units', 'Orders', 'SKU Count', 'Top SKU'], stateTableRows),
  '',
  '## Which states sell the most product',
  ...stateHighlights.map((line) => `- ${line}`),
  '',
  '## Best state for each SKU (top 25 by revenue)',
  makeMarkdownTable(['SKU Key', 'SKU Name', 'Revenue', 'Units', 'Orders', 'Top State', 'Top State Revenue', 'Top State Share'], skuTableRows),
  '',
  'The workflow output also includes full arrays for skuSummary (every SKU), stateTotals (every state), topSkusByState, and skuStateDetail.'
];

if (resolvedFieldLines.length) {
  markdownSections.push('', '## Resolved field paths', ...resolvedFieldLines);
}
if (warningLines.length) {
  markdownSections.push('', '## Warnings', ...warningLines);
}

const htmlSections = [
  '<h1>Supplier SKU State Sales Report</h1>',
  `<p><strong>Supplier:</strong> ${escapeHtml(metadata.supplier_name || normalisedRows[0].supplier_name)} (${escapeHtml(metadata.supplier_id || normalisedRows[0].supplier_id)})<br/><strong>Window:</strong> last ${escapeHtml(String(metadata.lookback_weeks || 52))} weeks</p>`,
  `<h2>Overall totals</h2><ul><li>Gross revenue: ${escapeHtml(money(overall.gross_revenue, currencySymbol))}</li><li>Units sold: ${escapeHtml(number(overall.units_sold))}</li><li>Orders: ${escapeHtml(number(overall.order_count))}</li><li>States with sales: ${escapeHtml(number(overall.state_count))}</li><li>SKUs with sales: ${escapeHtml(number(overall.sku_count))}</li></ul>`,
  '<h2>States ranked by revenue</h2>',
  makeHtmlTable(['Rank', 'State', 'Revenue', 'Units', 'Orders', 'SKU Count', 'Top SKU'], stateTableRows),
  '<h2>Which states sell the most product</h2>',
  `<ul>${stateHighlights.map((line) => `<li>${escapeHtml(line)}</li>`).join('')}</ul>`,
  '<h2>Best state for each SKU (top 25 by revenue)</h2>',
  makeHtmlTable(['SKU Key', 'SKU Name', 'Revenue', 'Units', 'Orders', 'Top State', 'Top State Revenue', 'Top State Share'], skuTableRows)
];

if (resolvedFieldLines.length) {
  htmlSections.push('<h2>Resolved field paths</h2>', `<ul>${resolvedFieldLines.map((line) => `<li>${escapeHtml(line.replace(/^- /, ''))}</li>`).join('')}</ul>`);
}
if (warningLines.length) {
  htmlSections.push('<h2>Warnings</h2>', `<ul>${warningLines.map((line) => `<li>${escapeHtml(line.replace(/^- /, ''))}</li>`).join('')}</ul>`);
}

return [{
  json: {
    metadata,
    warnings: metadata.warnings || [],
    overallTotals: overall,
    stateTotals,
    skuSummary,
    topSkusByState: stateTotals.map((entry) => ({ state_name: entry.state_name, top_skus: entry.top_skus })),
    skuStateDetail: normalisedRows,
    markdownReport: markdownSections.join('\n'),
    htmlReport: `<html><head><style>body{font-family:Arial,sans-serif;color:#222;line-height:1.4;}table{border-collapse:collapse;width:100%;margin-bottom:20px;}th,td{border:1px solid #ccc;padding:8px;text-align:left;}th{background:#f3f6fa;}tr:nth-child(even){background:#fafafa;}h1,h2{color:#1f4e79;}</style></head><body>${htmlSections.join('')}</body></html>`
  }
}];
